      "category": "Firewall"
    },
    {
      "id": "DOC-003",
      "title": "Router Restart Procedure",
      "content": "Step 1: Check active sessions. Step 2: Notify branch staff. Step 3: Execute 'reload' command. Step 4: Wait 5 minutes. Step 5: Verify connectivity.",
      "category": "Router"
    }
  ]
}

